index 2d7524e8018b..ea105a8426c0 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1366,8 +1366,44 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
       V2 = X;
     }
   }
+  // Handle (icmp ult X, C1) & (icmp eq (X & Mask), C2) where the mask check
+  // implies a range that is a subset of the range check.
+  // For (icmp eq (X & Mask), C2), if Mask has k trailing ones, the values that
+  // satisfy this are [C2, C2 + 2^k - 1]. If this range is a subset of [0, C1-1]
+  // (the range from ult X, C1), then the range check is redundant.
+  if (IsAnd && V1 != V2 && !MatchedAnd1 && !MatchedAnd2) {
+    // Check if we have (icmp ult X, C1) & (icmp eq (X & Mask), C2)
+    // or (icmp eq (X & Mask), C2) & (icmp ult X, C1)
+    Value *X;
+    const APInt *MaskC;
+    // Try: ICmp1 is the range check, ICmp2 is the mask check
+    if (Pred1 == ICmpInst::ICMP_ULT && Pred2 == ICmpInst::ICMP_EQ &&
+        match(V2, m_c_And(m_Specific(V1), m_APInt(MaskC)))) {
+      // V2 = (V1 & MaskC), check if [C2, C2 + 2^k - 1] is a subset of [0, C1-1]
+      // where k is the number of trailing ones in MaskC.
+      unsigned TrailingOnes = MaskC->countr_one();
+      if (TrailingOnes > 0) {
+        APInt RangeSize = APInt::getOneBitSet(C2->getBitWidth(), TrailingOnes);
+        // Check if C2 + RangeSize <= C1 (i.e., [C2, C2 + RangeSize) is a subset of [0, C1))
+        if (C2->ult(*C1) && (*C2 + RangeSize).ule(*C1)) {
+          // The mask check implies the range check, return the mask check.
+          return ICmp2;
+        }
+      }
+    }
+    // Try: ICmp2 is the range check, ICmp1 is the mask check
+    if (Pred2 == ICmpInst::ICMP_ULT && Pred1 == ICmpInst::ICMP_EQ &&
+        match(V1, m_c_And(m_Specific(V2), m_APInt(MaskC)))) {
+      unsigned TrailingOnes = MaskC->countr_one();
+      if (TrailingOnes > 0) {
+        APInt RangeSize = APInt::getOneBitSet(C1->getBitWidth(), TrailingOnes);
+        if (C1->ult(*C2) && (*C1 + RangeSize).ule(*C2)) {
+          return ICmp1;
+        }
+      }
+    }
+  }

